## 6. Full self‑contained listing

Below is the *exact* text you can copy‑paste into two files (`blocksci.mli` and `blocksci_stubs.c`) and compile as shown above.

```ocaml
(* ==== blocksci.mli ===================================================== *)
type block

val height    : block -> int
val hash      : block -> string
val timestamp : block -> int64

val iter_blocks     : (block -> unit) -> unit
val iter_blocks_exn : (block -> unit) -> unit
```

```c
/* ==== blocksci_stubs.c ================================================= */
/* Compile with a C++ compiler (g++ / clang++) */
#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/custom.h>

#include <BlockSci/Chain.h>   /* adjust path */
#include <BlockSci/Block.h>

using namespace blocksci;

/* ---------- custom value for a Block ----------------------------------- */
static void block_finalize(value v)
{
  Block **p = (Block **)Data_custom_val(v);
  delete *p;
}
static struct custom_operations block_ops = {
  "blocksci.block",
  block_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
  custom_hash_ext_default,
  custom_serialize_ext_default,
  custom_deserialize_ext_default
};

static value caml_wrap_block(Block *blk)
{
  value v = caml_alloc_custom(&block_ops, sizeof(Block *), 0, 1);
  *((Block **)Data_custom_val(v)) = blk;
  return v;
}

/* ---------- field accessors ------------------------------------------- */
CAMLprim value caml_blocksci_block_height(value vblk)
{
  CAMLparam1(vblk);
  Block *blk = *((Block **)Data_custom_val(vblk));
  CAMLreturn(Val_int(blk->height()));
}
CAMLprim value caml_blocksci_block_hash(value vblk)
{
  CAMLparam1(vblk);
  CAMLlocal1(vhash);
  Block *blk = *((Block **)Data_custom_val(vblk));
  std::string h = blk->hash();          /* binary 32‑byte hash */
  vhash = caml_copy_string(h.c_str());
  CAMLreturn(vhash);
}
CAMLprim value caml_blocksci_block_timestamp(value vblk)
{
  CAMLparam1(vblk);
  Block *blk = *((Block **)Data_custom_val(vblk));
  CAMLreturn(caml_copy_int64((int64_t)blk->timestamp()));
}

/* ---------- iterator core --------------------------------------------- */
static void iter_blocks_generic(value v_cb, int propagate_exn)
{
  CAMLparam1(v_cb);
  CAMLlocal1(v_block);

  try {
    Chain chain;                     /* global chain object */
    auto it  = chain.begin();
    auto end = chain.end();

    for (; it != end; ++it) {
      Block *blk = new Block(*it);
      v_block = caml_wrap_block(blk);
      value r = caml_callback_exn(v_cb, v_block);
      if (Is_exception_result(r)) {
        if (propagate_exn) caml_raise(Extract_exception(r));
        else break;
      }
      delete blk;   /* duplicate was already handed to OCaml */
    }
  } catch (std::exception const &e) {
    caml_failwith(e.what());
  }
  CAMLreturn0;
}

/* ---------- public entry points --------------------------------------- */
CAMLprim value caml_blocksci_iter_blocks(value v_cb)
{
  CAMLparam1(v_cb);
  iter_blocks_generic(v_cb, 0);
  CAMLreturn(Val_unit);
}
CAMLprim value caml_blocksci_iter_blocks_exn(value v_cb)
{
  CAMLparam1(v_cb);
  iter_blocks_generic(v_cb, 1);
  CAMLreturn(Val_unit);
}

/* ---------- optional registration (useful for Dune) ------------------- */
static struct caml_named_value {
  const char *name;
  value (*fn)(value);
} caml_prims[] = {
  {"blocksci_block_height", caml_blocksci_block_height},
  {"blocksci_block_hash", caml_blocksci_block_hash},
  {"blocksci_block_timestamp", caml_blocksci_block_timestamp},
  {"blocksci_iter_blocks", caml_blocksci_iter_blocks},
  {"blocksci_iter_blocks_exn", caml_blocksci_iter_blocks_exn},
  {NULL, NULL}
};

CAMLprim value caml_blocksci_register_prims(value unit)
{
  CAMLparam1(unit);
  for (int i = 0; caml_prims[i].name != NULL; ++i)
    caml_register_named_value(caml_prims[i].name, caml_prims[i].fn);
  CAMLreturn(Val_unit);
}
```

That’s it. Drop the two files into your project, compile the stub as C++, link with the real BlockSci library, and you have a **fast, idiomatic OCaml API** that lets your users write per‑block code just like they would with pandas or Polars. Happy hacking!
